import collections

class PlanarityChecks:
    def __init__(self, num_vertices):
        if num_vertices < 0:
            raise ValueError("Number of vertices cannot be negative.")
        self.n = num_vertices
        self.adj = [[] for _ in range(num_vertices)]
        self._all_edges = []

    def add_edge(self, u, v):
        if not (0 <= u < self.n and 0 <= v < self.n):
            raise IndexError("Vertex index out of bounds.")
        self.adj[u].append(v)
        if u != v:
            self.adj[v].append(u)
        self._all_edges.append(tuple(sorted((u, v))))

    def get_total_edges_count(self):
        return len(self._all_edges)

    def get_simple_edges_count(self):
        unique_simple_edges = set()
        for u, v in self._all_edges:
            if u != v:
                unique_simple_edges.add((u, v))
        return len(unique_simple_edges)

    def has_self_loops(self):
        for u, v in self._all_edges:
            if u == v:
                return True
        return False

    def has_multiple_edges(self):
        edge_counts = collections.Counter()
        for u, v in self._all_edges:
            if u != v:
                edge_counts[(u, v)] += 1
        for count in edge_counts.values():
            if count > 1:
                return True
        return False

    def is_simple(self):
        return not self.has_self_loops() and not self.has_multiple_edges()

    def is_connected(self):
        if self.n == 0:
            return True
        if self.n == 1:
            return True

        visited = [False] * self.n
        q = collections.deque()

        start_node = 0
        q.append(start_node)
        visited[start_node] = True
        count = 1

        while q:
            u = q.popleft()
            for v in self.adj[u]:
                if not visited[v]:
                    visited[v] = True
                    q.append(v)
                    count += 1
        return count == self.n

    def check_euler_bound_for_simple_graph(self):
        if self.n < 3:
            return True

        m_simple = self.get_simple_edges_count()
        return m_simple <= 3 * self.n - 6

    def is_small_graph_planar(self):
        return self.n <= 4

    def run_basic_checks(self):
        results = {}
        results["num_vertices"] = self.n
        results["total_edges_count"] = self.get_total_edges_count()
        results["simple_edges_count"] = self.get_simple_edges_count()
        results["has_self_loops"] = self.has_self_loops()
        results["has_multiple_edges"] = self.has_multiple_edges()
        results["is_simple"] = self.is_simple()
        results["is_connected"] = self.is_connected()
        results["satisfies_euler_bound_m_le_3n_minus_6"] = self.check_euler_bound_for_simple_graph()
        results["is_small_graph_planar"] = self.is_small_graph_planar()

        return results
